            }
		    break;
        case "pchsAdptMintCnt":
			if (ds_wrkList.getCellData(row, "pchsAdptMintCnt") == "") {
                ds_wrkList.setCellData(row, "pchsAdptMintCnt", 0);
            }
		    break;
        case "wrkWt":
			if (ds_wrkList.getCellData(row, "wrkWt") == "") {
                ds_wrkList.setCellData(row, "wrkWt", 0);
            }
		    break;
