scwin.rd_gubun_onviewchange = function (info) {
    if (rd_gubun.getValue() == "01"){
		$c.gus.cfDisableObjects([udc_eqCd]);
		ed_eqCd.setValue("");

		ds_condition.set("eqCd", "");
		ds_condition.set("eqNm", "");

	}else if (rd_gubun.getValue() == "02"){
		$c.gus.cfEnableObjects([udc_eqCd]);

	}
};


